def get_api_key() -> str:
    """Retrieve API key from environment variable. Never hardcode secrets."""
    api_key = os.environ.get("OPENAI_API_KEY")
    if not api_key:
        raise EnvironmentError(
            "OPENAI_API_KEY environment variable is not set. "
            "Set it securely via your environment or secrets manager."
        )
    return api_key


def sanitize_input(user_input: str) -> str:
    """Sanitize user input by removing potentially dangerous characters and patterns."""
    if not isinstance(user_input, str):
        raise ValueError("Input must be a string")

    # Strip leading/trailing whitespace
    sanitized = user_input.strip()

    # Enforce maximum length
    if len(sanitized) > MAX_MESSAGE_LENGTH:
        sanitized = sanitized[:MAX_MESSAGE_LENGTH]
        logger.info("User input truncated to maximum length")

    # Remove null bytes and other control characters (keep newlines and tabs)
    sanitized = re.sub(r'[\x00-\x08\x0b\x0c\x0e-\x1f\x7f]', '', sanitized)

    return sanitized


def detect_prompt_injection(user_input: str) -> bool:
    """Check for common prompt injection patterns. Returns True if injection detected."""
    for pattern in INJECTION_PATTERNS:
        if pattern.search(user_input):
            logger.warning("Potential prompt injection attempt detected")
            return True
    return False


def validate_conversation_history(conversation_history: list) -> bool:
    """Validate the conversation history structure and length."""
    if not isinstance(conversation_history, list):
        return False

    if len(conversation_history) > MAX_CONVERSATION_TURNS * 2:
        return False

    allowed_roles = {"user", "assistant"}
    for message in conversation_history:
        if not isinstance(message, dict):
            return False
        if "role" not in message or "content" not in message:
            return False
        if message["role"] not in allowed_roles:
            return False
        if not isinstance(message["content"], str):
            return False
        if len(message["content"]) > MAX_MESSAGE_LENGTH:
            return False

    return True


class CustomerSupportChatbot:
    """Secure customer support chatbot using OpenAI API."""

    def __init__(self, model: str = "gpt-4o-mini"):
        if model not in ALLOWED_MODELS:
            raise ValueError(f"Model must be one of: {ALLOWED_MODELS}")

        self.model = model
        self.client = OpenAI(api_key=get_api_key())
        self.conversation_history: list[dict[str, str]] = []
        logger.info("Chatbot initialized with model: %s", self.model)

    def _build_messages(self, user_message: str) -> list[dict[str, str]]:
        """
        Build the messages array with strict separation between
        system instructions and user content.

        The system prompt is ALWAYS the first message and is never
        concatenated with or influenced by user input.
        """
        messages = [
            {"role": "system", "content": SYSTEM_PROMPT}
        ]

        # Add conversation history (already validated)
        messages.extend(self.conversation_history)

        # Add current user message as a distinct user role message
        messages.append({"role": "user", "content": user_message})

        return messages

    def send_message(self, user_input: str) -> str:
        """
        Process a user message and return the assistant's response.

        Applies input validation, injection detection, and secure API usage.
        """
        # Step 1: Sanitize input
        sanitized_input = sanitize_input(user_input)

        if not sanitized_input:
            return "I didn't receive a message. Could you please try again?"

        # Step 2: Check for prompt injection
        if detect_prompt_injection(sanitized_input):
            logger.warning("Prompt injection blocked")
            return (
                "I'm here to help with customer support questions. "
                "Could you please rephrase your question about our products or services?"
            )

        # Step 3: Validate conversation history hasn't been tampered with
        if not validate_conversation_history(self.conversation_history):
            logger.error("Conversation history validation failed, resetting")
            self.conversation_history = []

        # Step 4: Check conversation length limits
        if len(self.conversation_history) >= MAX_CONVERSATION_TURNS * 2:
            # Trim oldest messages, keeping recent context
            self.conversation_history = self.conversation_history[-(MAX_CONVERSATION_TURNS):]
            logger.info("Conversation history trimmed to maintain limits")

        # Step 5: Build messages with strict role separation
        messages = self._build_messages(sanitized_input)

        # Step 6: Call OpenAI API
        try:
            response = self.client.chat.completions.create(
                model=self.model,
                messages=messages,
                max_tokens=1000,
                temperature=0.7,
                # Limit response to text only
                top_p=1.0,
                frequency_penalty=0.0,
                presence_penalty=0.0,
            )

            assistant_message = response.choices[0].message.content

            if not assistant_message:
                return "I'm sorry, I couldn't generate a response. Please try again."

            # Step 7: Sanitize output (remove any accidentally leaked sensitive patterns)
            assistant_message = re.sub(
                r'sk-[a-zA-Z0-9]{20,}', '[REDACTED]', assistant_message
            )

            # Step 8: Update conversation history
            self.conversation_history.append(
                {"role": "user", "content": sanitized_input}
            )
            self.conversation_history.append(
                {"role": "assistant", "content": assistant_message}
            )

            return assistant_message

        except Exception as e:
            # Log error without exposing sensitive details to user
            logger.error("API call failed: %s", type(e).__name__)
            return (
                "I'm experiencing a temporary issue. "
                "Please try again in a moment or contact our support team directly."
            )

    def reset_conversation(self) -> None:
        """Reset the conversation history."""
        self.conversation_history = []
        logger.info("Conversation history reset")


